function ModelFunctionOpen:OnForeshowPopRecrodReq(refId)
    local pb = LProtoHelper.CreateProto(LProtoIds.ForeshowPopRecrodReq)
    pb.refId = refId
    SendMessage(pb,LProtoIds.ForeshowPopRecrodReq)
end
function ModelFunctionOpen:OnForeshowPopResp(pb)
    local foreshowMap = {}
    if not self._foreshowPopList then 
        self._foreshowPopList = {}
    else
        for index, info in ipairs(self._foreshowPopList) do
            foreshowMap[info.refId] = index
        end
    end
    for k, v in ipairs(pb.foreshowPops or {}) do
        local indx = foreshowMap[v.refId]
        if indx then 
            self._foreshowPopList[indx] = {refId =v.refId,isPop = v.isPop ,endTime = tonumber(v.endTime)}
        else
            table.insert(self._foreshowPopList,{refId =v.refId,isPop = v.isPop ,endTime = tonumber(v.endTime)})
        end
    end
end


