function ModelFunctionOpen:OnRangeParaCheck(type, oldPara, newPara)
    if not self._isFinished then
        return
    end

    local checkMap = self._checkMapByType[type]
    if not checkMap then
        return
    end

    for i = oldPara + 1, newPara do
        if checkMap[i] then
            self:OnFunctionOpenStateChange()
            return
        end
    end
end

function ModelFunctionOpen:OnPointParaCheck(type, paraList)
    if not self._isFinished then
        return
    end

    local checkMap = self._checkMapByType[type]
    if not checkMap then
        return
    end

    for k, v in ipairs(paraList) do
        if checkMap[v] then
            self:OnFunctionOpenStateChange()
            return
        end
    end
end

function ModelFunctionOpen:OnFunctionOpenStateChange()
    if not self._isFinished then
        return
    end
    FireEvent(EventNames.REFRESH_FUNCTION_STATE)
    printInfoN(" ------ EventNames.REFRESH_FUNCTION_STATE")
    -- self:CheckPreFuncOpen()【G功能预告】删除玩法预告机制（客户端&服务端
    -- self:RecordPreFuncOpen()【G功能预告】删除玩法预告机制（客户端&服务端
end

