function ModelFunctionOpen:ParseConfig()
    self._isParseConfig = true


    self._pathToId = {}
    self._groupFunctions = {}
    self._extraConditions = {}
    self._btnIndexs = {}

    self._openConditions = {}
    self._otherOpenCondition = {}

    self._checkMapByType = {}

    for k, v in pairs(GameTable.FeatureOpenRef) do
        local path = v.uiLevel
        local refId = v.refId
        self._pathToId[path] = refId

        local group = v.frameGroup
        if group > 0 then
            local dataList = self._groupFunctions[group]
            if not dataList then
                dataList = {}
                self._groupFunctions[group] = dataList
            end

            table.insert(dataList, refId)
        end

        local btnIndex = v.btnIndex
        self._btnIndexs[k] = self:ParseBtnIndex(btnIndex)

        local open = v.open
        local condition = self:ParseCondition(open)
        self._openConditions[k] = condition
        local otherOpen = v.otherOpen
        local otherCondition = self:ParseCondition(otherOpen)
        self._otherOpenCondition[k] = otherCondition

        for k, v in ipairs(condition) do
            local type = v.type
            local para = v.para
            local checkMap = self._checkMapByType[type]
            if not checkMap then
                checkMap = {}
                self._checkMapByType[type] = checkMap
            end

            checkMap[para] = true
        end

        for k, v in ipairs(otherCondition) do
            local type = v.type
            local para = v.para
            local checkMap = self._checkMapByType[type]
            if not checkMap then
                checkMap = {}
                self._checkMapByType[type] = checkMap
            end

            checkMap[para] = true
        end


    end

end

