function ModelFunctionOpen:CheckIsShow(refId)
    --if refId == 10303000 then return true end

    local isAreaOpen = self:CheckAreaOpen(refId)
    if not isAreaOpen then
        local refItem = self:GetAreaOpenRef(refId)
        return refItem.show == 1
    end
    if not self:CheckIsOpenRes(refId) then
        return false
    end
    local isOpen = self:CheckIsOpened(refId)
    if not isOpen then
        local cfg = GameTable.FeatureOpenRef[refId]
        if cfg then
            return cfg.show == 1
        end
    end

    return true
end

