function ModelFunctionOpen:GetOpenLv(refId)
    local cfg = GameTable.FeatureOpenRef[refId]
    if not cfg or cfg.open == "" then
        return 0
    end
    local openArr = string.split(cfg.open, "=")
    return tonumber(openArr[2])
end

function ModelFunctionOpen:CheckIsOpened(refId, showTip)
    --if refId == 10303000 then return true end
    if not self:CheckAreaOpen(refId, showTip) then
        return
    end

    local cfg = GameTable.FeatureOpenRef[refId]
    if not cfg then
        return false, ''
    end

    if not self._functionOpenCache then
        self._functionOpenCache = {}
    end

    local cache = self._functionOpenCache[refId]
    if cache then
        return cache
    end

    local noCache = false
    local conditions = self._openConditions[refId]

    local extraParaList = LxDataHelper.ParseNumber_Sign(cfg.btnIndex, ',')
    local uniqueJump = extraParaList[3]
    local isOpen = true
    for k, v in ipairs(conditions) do
        local type = v.type

        local para = v.para

        if not noCache then
            noCache = self._noCacheType[type]
        end

        local checkFunc = self._checkFuncs[type]
        if checkFunc then
            isOpen = checkFunc(para, uniqueJump)
            if not isOpen then
                break
            end
        end
    end

    if isOpen then
        isOpen = self:CheckIsOpenRes(refId)
    end

    if not isOpen then

        local otherConditions = self._otherOpenCondition[refId]
        if #otherConditions > 0 then
            isOpen = true
            for k, v in ipairs(otherConditions) do
                local type = v.type
                local para = v.para

                if not noCache then
                    noCache = self._noCacheType[type]
                end

                local checkFunc = self._checkFuncs[type]
                if checkFunc then
                    isOpen = checkFunc(para, uniqueJump)
                    if not isOpen then
                        break
                    end
                end
            end
        end
    end

    if refId == ModelFunctionOpen.WONDER_HARD then
        local isPass = gModelWonderland:CheckSelectPattern(ModelWonderland.HARD)
        isOpen = isOpen and isPass
    elseif refId == ModelFunctionOpen.WONDER_TOUGH then
        local isPass = gModelWonderland:CheckSelectPattern(ModelWonderland.TOUGH)
        isOpen = isOpen and isPass
    end

    --if isOpen then
    --    if refId == ModelFunctionOpen.DREAMTRIP_ENTER then
    --        isOpen = gModelFastDreamTrip:CheckIsOpenDay()
    --    end
    --end

    local msg = ccLngText(cfg.openDesc)
    if not isOpen and showTip then

        GF.ShowMessage(msg)
    end


    local useCache = true
    if not string.isempty(cfg.resOpen) then
        useCache = false
    end
    if isOpen and not noCache and useCache then
        self._functionOpenCache[refId] = true
    end

    return isOpen, msg
end


function ModelFunctionOpen:CheckCondition(open)
    local conditions = self:ParseCondition(open)
    local isOpen = true
    for k, v in ipairs(conditions) do
        local type = v.type

        local para = v.para

        if not noCache then
            noCache = self._noCacheType[type]
        end

        local checkFunc = self._checkFuncs[type]
        if checkFunc then
            isOpen = checkFunc(para, uniqueJump)
            if not isOpen then
                break
            end
        end
    end


end

