function ModelFunctionOpen:CheckDate(para)

    local sign = string.sub(para, 1, 1)
    local year, month, day

    local isBefore
    if sign == "-" then
        isBefore = true
        year = tonumber(string.sub(para, 2, 5))
        month = tonumber(string.sub(para, 6, 7))
        day = tonumber(string.sub(para, 8, 9))
    else
        isBefore = false
        year = tonumber(string.sub(para, 1, 4))
        month = tonumber(string.sub(para, 5, 6))
        day = tonumber(string.sub(para, 7, 8))
    end

    local date = LUtil.OSDate("*t", GetTimestamp())
    local curYear = date.year
    local curMonth = date.month
    local curDay = date.day

    if isBefore then
        if curYear > year then
            return false
        elseif curYear == year then
            if curMonth > month then
                return false
            elseif curMonth == month then
                if curDay > day then
                    return false
                end
            end
        end
    else
        if curYear < year then
            return false
        elseif curYear == year then
            if curMonth < month then
                return false
            elseif curMonth == month then
                if curDay < day then
                    return false
                end
            end
        end
    end

    return true
end

function ModelFunctionOpen:CheckDYOpt(para)
    local typeNum = checknumber(para) or 0
    if typeNum == 1 then
        local IsCanShowScene = gLSdkImpl and gLSdkImpl:CallMethod(LSdkMethod.IsCanShowScene)
        if LOG_INFO_ENABLED then
            local openStr = IsCanShowScene and "1" or "0"
            printInfo("ModelFunctionOpen", "是否可以显示侧边栏相关功能 "..openStr)
        end
        -- 是否可以显示侧边栏相关功能
        return IsCanShowScene
    end
    return true
end

