function ModelFunctionOpen:IsMeetBattleNumByDiffLvl(para, diffLvl)
    local battleNum = gModelInstance:GetPassedBattleNum(diffLvl)
    local meet = battleNum >= para
    local str = ""
    if not meet then
        local chapterId = gModelInstance:GetMissionChapterIdByNum(para, diffLvl)--获取关卡的名字
