function ModelFunctionOpen:ParseCondition(str)
    if string.isempty(str) then
        return {}
    end
    local conditions = {}
    local strs = string.split(str, ",")
    for k, v in ipairs(strs) do
        local temp = string.split(v, '=')
        if #temp == 2 then
            local type = tonumber(temp[1])
            local para = tonumber(temp[2])
            local data = {
                type = type,
                para = para,
            }
            table.insert(conditions, data)
        end
    end

    return conditions
end

function ModelFunctionOpen:ModifyFunc(rootName, tran, func)
    local modifyFun = func
    local path = nil
    if self:IsFinished() then
        path = LxUiHelper.GetRelativePath(rootName, tran)
        if path then
            local functionRefId = self:GetRefIdByPath(path)
            if functionRefId then
                modifyFun = function()
                    if self:CheckIsOpened(functionRefId, true) then
                        if func then
                            func()
                        end

                        gModelRedPoint:OnClickFunc(functionRefId) --点击消失的红点处理
                    end
                end
            end
        end
    end

    return modifyFun
end

function ModelFunctionOpen:Jump(functionOpenId, srcWnd, func, para)
    if LOG_INFO_ENABLED then
        printInfoN(string.format("function jump refId %s", tostring(functionOpenId)))
    end
    if not functionOpenId then
        return
    end
    local cfg = GameTable.FeatureOpenRef[functionOpenId]
    if not cfg then
        if LOG_INFO_ENABLED then
            printInfoN("not functionOpenRef refId" .. functionOpenId)
        end
        return
    end

    local isOpen = self:CheckIsOpened(functionOpenId, true)
    if not isOpen then
        if LOG_INFO_ENABLED then
            printInfoN("function not open" .. functionOpenId)
        end
        return
    end

    local map = cfg.map    -- 地图名    LCityMap,LFightIdleMap,LSuburbMap,LFightMap
    local pagePara = self:ModifyWndPara(functionOpenId)
    local wndName = cfg.wndName  -- 界面名
    local combatTypeList = self:GetFuncRelaCombat(functionOpenId)

    local sensitiveList = {
        ["UISayAirWin"] = true,
        ["UISayPop"] = true,
        ["UISayFlow"] = true,
        ["UISagaComment"] = true,
        ["UIBulletSaySendPop"] = true,
        ["UIInvasionSay"] = true,
    }
    if sensitiveList[wndName] then
        local sensitive = gModelPlayer:GetChatForbid(ModelPlayer.SENSITIVE_TYPE_1)
        if not sensitive then
            GF.ShowMessage(ccClientText(30800))
            return
        end
    end


    -- 个人信息界面需要请求信息后打开
    --if wndName == "UIPersonAreaWin" then
    --	local playerId = gModelPlayer:GetPlayerId()
    --	gModelPlayerSpace:OpenSpaceWnd(playerId)
    --	return
    --end

    local skipSave = false
    local uilayer = cfg.uilayer    -- 界面层级
    local jumpType = cfg.jumpType
    if jumpType == 10 then
        --- 侧边栏跳转
        gLSdkImpl:CallMethod(LSdkMethod.NavigateToScene)
        return
    end
    
    
    if jumpType == 3 then
        if functionOpenId ~= 12100000 then
            local has = gModelGuild:GetBHaveGuild()
            if not has then
                local str = ccClientText(12567)
                GF.ShowMessage(str)
                return
            end
        end
    -- elseif jumpType == 4 then
    --     local isInMap = gModelWonderland:IsInMap()

    --     if functionOpenId == 16800010 then
    --         if not isInMap then
    --             return
    --         end
    --     elseif functionOpenId == 16800020 then
    --         if isInMap then
    --             return
    --         end
    --     end

    --     local temp = isInMap and "UIEden" or "UIEdenFront"
    --     gLGameUI:SaveBackWnd(temp)
    --     skipSave = true
    elseif jumpType == 4 then
        --map = ""
        skipSave = true
    elseif jumpType == 8 then
        skipSave = true
    end

    if not skipSave then
        gLGameUI:SaveBackWnd(wndName)
    end

    FireEvent(EventNames.ON_JUMP)

    local mainBtnIndex = pagePara.mainIndex or 0
    local page = pagePara.page or 0
    local subPage = pagePara.subPage or 0

    local isFight = false
    local combatType = nil
    for k, v in pairs(combatTypeList) do
        isFight = gLFightManager:IsCombatTypeInFight(k)
        if isFight then
            combatType = k
            break
        end
    end

    local exceptsWnd = {}    --需要保留的界面

    if jumpType == 1 and srcWnd then
        self:AddWndRecord(exceptsWnd, srcWnd)
    end

    if isFight then
        gLFightManager:PrepareGoToBattle(combatType, {})
        self:AddWndRecord(exceptsWnd, "UIFight")
        return exceptsWnd, true
    else
        if not string.isempty(map) then
            if GF.GetCurMap():IsSameMap(map) and map == "LFightIdleMap" then
            else
                GF.ChangeMap(map)
            end
        end

        local jumpMapPos = cfg.jumpMapPos --主场景跳转至指定坐标
        local curMap = GF.GetCurMap()

        if not string.isempty(jumpMapPos) then
            local pos = LxDataHelper.ParseVector(jumpMapPos)
            if curMap and curMap.MoveCamera then
                curMap:MoveCamera(pos, nil, 0)
            end
        end

        local isIgnore = false
        local closeWndList = {}  --需要关闭的界面
        local closeAll = false   --是否清理全部界面
        if jumpType == 2 then
            self:AddWndRecord(closeWndList, srcWnd)
        elseif jumpType == 3 then
            if not gModelGuild:GetBHaveGuild() then
                --local wndSeekPop = gLGameLanguage:IsUSARegion() and "UIGdSeekPopEn" or "UIGdSeekPop"
                local wndSeekPop = "UIGdSeekPop"
                GF.OpenWndBottom(wndSeekPop)
                isIgnore = true
                self:AddWndRecord(exceptsWnd, wndSeekPop)
            end
        elseif jumpType == 4 then
            -- if functionOpenId == 16800000 then
            --     local isInMap = gModelWonderland:IsInMap()
            --     if isInMap then
            --         --gLGameUI:SaveBackWnd("UIEden")
            --         GF.OpenWndBottom("UIEden")
            --         gModelWonderland:EnterWonderMap()
            --         self:AddWndRecord(exceptsWnd, "UIEden")
            --     else
            --         --gLGameUI:SaveBackWnd("UIEdenFront")
            --         GF.OpenWndBottom("UIEdenFront")
            --         GF.ChangeMap("LCityMap")
            --         self:AddWndRecord(exceptsWnd, "UIEdenFront")
            --     end

            --     closeAll = true
            --     isIgnore = true
            -- end
            if functionOpenId == ModelDesireTrail.MainFuncId then
                closeAll = true
                --isIgnore = true

                gModelGeneral:DesireTrailEntrance()
                self:AddWndRecord(exceptsWnd, "UIDesireTrail")
            end

        elseif jumpType == 5 then
            closeAll = true
            FireEvent(EventNames.SHOW_MAIN_MORE_FUN, false)
        elseif jumpType == 8 then
            --[[            if functionOpenId == 17100400 then
                            local isSelMap = gModelDreamTrip:IsSelMap()
                            if isSelMap then
                                local selHeroList = gModelDreamTrip:GetSelHeroList()
                                if #selHeroList < 1 then
                                    GF.OpenWnd("UIHopeSelSaga",{func = func})
                                    self:AddWndRecord(exceptsWnd,"UIHopeSelSaga")
                                else
                                    GF.ChangeMap("LDreamTripMap",true,{isFirst = self._isFirst,mapType = ModelCommonDreamTrip.MAP_TYPE_NORMAL})
                                    GF.OpenWndBottom("UIHope")
                                    self:AddWndRecord(exceptsWnd,"UIHope")
                                end
                            else
                                GF.OpenWnd("UIHopeMin",{func = func})
                                self:AddWndRecord(exceptsWnd,"UIHopeMin")
                            end
                            closeAll = true
                            isIgnore = true
                        end]]
        elseif jumpType == 9 then
            local wndIns = GF.FindFirstWndByName("UIBadgeWear")
            if wndIns then
                GF.CloseWndByName("UIBadgeWear")
            end
            closeAll = true
            FireEvent(EventNames.SHOW_MAIN_MORE_FUN, false)
            GF.OpenWndBottom("UIGenWin")
            self:AddWndRecord(exceptsWnd, "UIGenWin")
        end

        --if functionOpenId == ModelFunctionOpen.ONE_NIGHT then
        --    isIgnore = true
        --    gModelOneNight:Entrance()
        --
        --    self:AddWndRecord(exceptsWnd,"UIOneNightSpaceOpenEffect")
        --    self:AddWndRecord(exceptsWnd,"UIOneNightSpaceCreate")
        --end

        --if curMap and curMap:IsSameMap("LOneNightSpaceMap") then
        --	self:AddWndRecord(exceptsWnd,"WndOneNightSpaceMain")
        --	self:AddWndRecord(exceptsWnd,"UIOneNightSpaceOrnament")
        --
        --end

        if string.isempty(wndName) then
            if LOG_INFO_ENABLED then
                printInfoN(string.format("jump para wndname is null refId %s", functionOpenId))
            end
            isIgnore = true
        end

        if not isIgnore then
            local arg = {}
            arg.jumpCallback = func
            arg.isFromJump = true
            arg.functionId = functionOpenId
            if para then
                arg.isFromBubble = para.isFromBubble
                arg.goodsId = para.goodsId
                arg.itemId = para.itemId

                if para.privilegeGiftRef then
                    arg.ref = para.privilegeGiftRef
                end
            end

            if wndName == "UIDian" and page == ModelShop.ACTIVITY then
                subPage = gModelActivity:GetSidByUniqueJump(subPage)
            end

            if page > 0 then
                arg.page = page
            end
            if subPage > 0 then
                arg.subPage = subPage
            end

            local extra = gModelNormalActivity:GetRefIdByJumpId(functionOpenId)
            if extra then
                arg.extra = extra
            end

            if wndName == "WndCrossServerChampion" or wndName == "WndCrossServerLadder" then
                -- 跨服里面有独立商店，调整会有问题，加额外代码处理
                GF.CloseWndByName("WndCrossServerChampion")
                GF.CloseWndByName("WndCrossServerLadder")

            end
            if wndName == "UIFarmHappy" then--临时处理
                local sid = gModelActivity:GetSidByUniqueJump(subPage)
                arg.activityData = gModelActivity:GetActivityBySid(sid)
                arg.playerId = gModelPlayer:GetPlayerId()
            end


            self:AddWndRecord(exceptsWnd, wndName)
            gLGameUI:OpenWndWithLayer(uilayer, wndName, arg)
        end

        if mainBtnIndex > 0 then
            local sendData = {
                index = mainBtnIndex,
                extraWnds = exceptsWnd,
            }
            FireEvent(EventNames.ONLY_CHANGE_MAIN_BTN_ON, sendData)
        end

        if closeAll then

            gLGameUI:CloseAllButExcept(exceptsWnd)
        else
            for k, v in pairs(closeWndList) do
                if not exceptsWnd[k] then
                    GF.CloseWndByName(k)
                end
            end
        end

        return exceptsWnd, true
    end
end

function ModelFunctionOpen:AddWndRecord(dataMap, wndName)
    if string.isempty(wndName) then
        return
    end
    if dataMap[wndName] then
        return
    end

    dataMap[wndName] = true
end

function ModelFunctionOpen:ModifyWndPara(refId)
    local group = GameTable.FeatureOpenRef[refId].frameGroup
    if group <= 0 or group == 8 or group == 9 then
        ---商店的使用id
        return self._btnIndexs[refId]
    end

    local dataList = self._groupFunctions[group]
    local hideIndex = {}
    for k, v in ipairs(dataList) do
        local isShow = self:CheckIsShow(v)
        if not isShow then
            local btnIndex = self._btnIndexs[v]
            if not table.isempty(btnIndex) then
                if btnIndex.subPage > 0 then
                    table.insert(hideIndex, btnIndex.subPage)
                elseif btnIndex.page > 0 then
                    table.insert(hideIndex, btnIndex.page)
                end
            end
        end
    end

    local selfBtnIndex = self._btnIndexs[refId]

    local btnIndex = table.clone(selfBtnIndex)
    if selfBtnIndex.subPage > 0 then
        for k, v in ipairs(hideIndex) do
            if selfBtnIndex.subPage > v then
                btnIndex.subPage = btnIndex.subPage - 1
            end
        end
    elseif selfBtnIndex.page > 0 then
        for k, v in ipairs(hideIndex) do
            if selfBtnIndex.page > v then
                btnIndex.page = btnIndex.page - 1
            end
        end
    end

    return btnIndex
end

function ModelFunctionOpen:ParseBtnIndex(str)
    if string.isempty(str) then
        return { mainIndex = 0, page = 0, subPage = 0 }
    end

    local t = {}
    local s, e, cap1, cap2, cap3 = string.find(str, "(%d+),(%d+),(%d+)")
    if cap1 and cap2 and cap3 then
        t.mainIndex = tonumber(cap1)
        t.page = tonumber(cap2)
        t.subPage = tonumber(cap3)
    end
    return t
end

