function ModelFunctionOpen:GetLevelLimit(refId)
    if not self._openConditions then
        return 1
    end
    local limit = self._openConditions[refId]
    if not limit then
        return 1
    end
    for k, v in ipairs(limit) do
        local type = v.type
        local para = v.para
        if type == 1 then
            return para
        end
    end

    return 1
end

