function ModelFunctionOpen:CheckShowMainTop()

    local guideType = gModelGuide:GetGuideType()
    local funcId = 10000011
    if guideType == 2 then
        funcId = 50400001
    elseif guideType == 3 then
        funcId = 50400002
    elseif guideType == 5 then
        funcId = 50400005
    end

    local isShow = self:CheckIsShow(funcId)
    return isShow or self._debugTag
end

function ModelFunctionOpen:CheckShowHurdle()
    local funcId = 10000012
    local isShow = self:CheckIsShow(funcId)
    return isShow or self._debugTag
end

function ModelFunctionOpen:DebugTag()
    self._debugTag = true

    FireEvent(EventNames.REFRESH_FUNCTION_STATE)
end

function ModelFunctionOpen:CheckOpenCondition(open)
    local conditions = self:ParseCondition(open)
    for k, v in ipairs(conditions) do
        local type = v.type
        local para = v.para
        local checkFunc = self._checkFuncs[type]
        if checkFunc then
             if not checkFunc(para) then
                return false
             end
        end
    end

    return true
end

function ModelFunctionOpen:GetOpenCondition(openPara, showTips)
    local conditions = self:ParseCondition(openPara)
    local meet = true
    local meetStr = ""
    for k, v in ipairs(conditions) do
        local type = v.type
        local para = v.para
        local checkFunc = self._checkOpenTipsFuncs[type]
        if checkFunc then
            meet, meetStr = checkFunc(para)
            if not meet then
                break
            end
        end
    end
    if showTips and not meet then
        GF.ShowMessage(meetStr)
    end
    return meetStr
end

