function ModelFunctionOpen:IsTodayNoTip()
    local recordTime = tonumber(LPlayerPrefs.prePostAlert) or 0

    local dayPast = LUtil.GetDayPast(recordTime)
    if dayPast < 2 then
        return true
    end

    return false
end


