function ModelFunctionOpen:GetFuncRelaCombat(refId)
    local parseFunc = function(value)
        local numList = LxDataHelper.ParseNumber_Sign(value, ",")
        local record = {}
        for k, v in ipairs(numList) do
            if v > 0 then
                record[v] = true
            end
        end

        return record
    end

    local value = self:GetConfigValueImpl(ModelFunctionOpen.FeatureOpenRef, refId, "combatType", parseFunc) or {}
    return value

end

function ModelFunctionOpen:GetOpenPara(refId, type)
    local conditions = self._openConditions[refId]
    for k, v in pairs(conditions) do
        if v.type == type then
            return v.para
        end
    end
end
---1,可领取 2,不可领取 3,已领取
function ModelFunctionOpen:GetForeFuncState(refId)
    local isRewarded = self._receiveForeIdMap and self._receiveForeIdMap[refId]
    if isRewarded then
        return 3
    else
        local ref = self:GetModelConfig(ModelFunctionOpen.FeaturePreviewAllRef)
        local data = ref[refId]
        local isOpen = self:CheckIsOpened(data.functionOpen)
        if isOpen then
            return 1
        else
            return 2
        end
    end
end

function ModelFunctionOpen:GetSortForeList()
    local ref = self:GetModelConfig(ModelFunctionOpen.FeaturePreviewAllRef)
    local dataList = {}

    local limitCnt = self:GetForShowPara("listMax")
    local notOpenList = {}
    for k, v in pairs(ref) do

        if not self:CheckRefDisable(ModelFunctionOpen.FORESHOWALL, v.refId) then
            local state = self:GetForeFuncState(v.refId)
            local data = {
                conf = v,
                state = state
            }

            if state == 1 then
                table.insert(dataList, data)
            elseif state == 2 then
                table.insert(notOpenList, data)
            end
        end

    end

    table.sort(notOpenList, function(a, b)
        return a.conf.sort < b.conf.sort
    end)

    for k, v in ipairs(notOpenList) do
        if k <= limitCnt then
            table.insert(dataList, v)
        else
            break
        end
    end

    table.sort(dataList, function(a, b)
        if a.state ~= b.state then
            return a.state < b.state
        end

        return a.conf.sort < b.conf.sort
    end)

    return dataList
end

function ModelFunctionOpen:GetForeAdList()
    local ref = self:GetModelConfig(ModelFunctionOpen.FeaturePreviewAllRef)
    local canGetList = {}
    local notOpenList = {}

    local limitCnt = self:GetForShowPara("cityListMax")
    limitCnt = limitCnt and limitCnt  or 0
    for k, v in pairs(ref) do

        if not self:CheckRefDisable(ModelFunctionOpen.FORESHOWALL, v.refId) then
            local state = self:GetForeFuncState(v.refId)

            if state == 1 then
                table.insert(canGetList, v)
            elseif state == 2 then
                table.insert(notOpenList, v)
            end
        end

    end

    if #canGetList > 0 then
        table.sort(canGetList, function(a, b)
            return a.sort < b.sort
        end)

        local list = {}

        for k, v in ipairs(canGetList) do
            if k <= limitCnt then
                table.insert(list, v)
            else
                break
            end
        end

        return list
    elseif #notOpenList > 0 then
        table.sort(notOpenList, function(a, b)
            return a.sort < b.sort
        end)

        return { notOpenList[1] }
    end

    return {}
end

function ModelFunctionOpen:GetForShowPara(key)
