end

function ModelFunctionOpen:GetWndRelaCombatType(wndName)
    local wndRelaMap = self._wndRelaMap
    if not wndRelaMap then
        wndRelaMap = {}
        local ref = self:GetModelConfig(ModelFunctionOpen.FeatureOpenRef)
        for k, v in pairs(ref) do
            local temp = v.wndName
            if not string.isempty(temp) and not wndRelaMap[temp] then
                local record = self:GetFuncRelaCombat(v.refId)
                if table.keysize(record) > 0 then
                    wndRelaMap[temp] = record
                end
            end
        end

        self._wndRelaMap = wndRelaMap
    end

    return wndRelaMap[wndName]
end

function ModelFunctionOpen:CheckAreaOpen(refId, showTip)
    local refItem = self:GetAreaOpenRef(refId)
    if refItem and refItem.openState == 1 then
        if showTip then
            GF.ShowMessage(ccLngText(refItem.openTips))
        end
        return false
    end

    return true
end

function ModelFunctionOpen:GetAreaOpenRef(refId)
    local ref = self:GetModelConfig(ModelFunctionOpen.FeatureOpenAreaRef)
    local refItem = ref[refId]
    return refItem
end

function ModelFunctionOpen:CheckRefDisable(type, refId)

    local maskDataMap = self._maskRefMap
    if not maskDataMap then
        maskDataMap = {}
        self._maskRefMap = maskDataMap
        local ref = self:GetModelConfig(ModelFunctionOpen.FeatureOpenAreaSublistRef)
        for k, v in pairs(ref) do
            local list = maskDataMap[v.type]
            if not list then
                list = {}
                maskDataMap[v.type] = list
            end
            table.insert(list, v)
        end


    end

    local isMask = false
    local dataList = maskDataMap[type]
    if not dataList then
        return isMask
    end
    for k, v in ipairs(dataList) do

        if not self:CheckAreaOpen(v.functionOpen) then
            if refId >= v.shieldMin and refId <= v.shieldMax then
                isMask = true
                break
            end
        end

    end

    if isMask then
        printInfoN2("地区屏蔽", string.format("屏蔽配置 type: %s,refId %s", type, refId))
    end

    return isMask
end

-- 主界面滚屏预告配置表
function ModelFunctionOpen:GetForeshowRefList()
    if not self._foreshowScrollList then
        local ref = self:GetModelConfig(ModelFunctionOpen.FeaturePreviewScrollRef) or {}
        local list = {}
        for _, v in pairs(ref) do
            table.insert(list, v)
        end
        self._foreshowScrollList = list
    end
    return self._foreshowScrollList
end

-- true,表示玩法可以显示
function ModelFunctionOpen:CanForeshow(data, refId)
    data = data or self._preFuncPlayMap[refId]
    if not data then
        return false
    end

    if data.startTime == -1 then
        return false
    end

    if data.endTime == 0 then
        return true
    end

    if data.endTime <= data.startTime then
        return false
    end

    local curTime = GetTimestamp()
    if curTime <= data.endTime and curTime >= data.startTime then
        return true
    end
    return false
end

