-- 获取主界面滚屏预告表
function ModelFunctionOpen:GetForeshowList(needSort)
    local funcList = {}
    if PRODUCT_G_VER == 1 or PRODUCT_G_VER == 2 then
        return funcList
    end
    -- for k, v in ipairs(self:GetForeshowRefList()) do
    --     if self:CheckIsOpened(v.functionOpen, false) and self:CanForeshow(nil, v.refId) then
    --         table.insert(funcList, v)
    --     end
    -- end

    local ForeshowScrollRef = GameTable.FeaturePreviewScrollRef
    for refId, data in pairs(self._preFuncPlayMap) do
        local ref = ForeshowScrollRef[refId]
        if ref and self:CheckIsOpened(ref.functionOpen, false) and self:CanForeshow(data) then
            table.insert(funcList, ref)
        end
    end

    local activeList = gModelActivity:GetMainEntranceActivityList()

    local EntranceType = ModelFunctionOpen.EntranceType

    local list = {}
    local index = 1
    for k, v in ipairs(activeList) do
        index = index + 1
        table.insert(list, { type = EntranceType.Activity, index = index, pb = v, data = self:ParseActivityConfig(v) })
    end
    for k, v in ipairs(funcList) do
        index = index + 1
        table.insert(list, { type = EntranceType.Func, index = index, data = v})
    end
    if needSort then
        table.sort(list, function(a, b)
            -- if a.data.sort ~= b.data.sort then
            --     return a.data.sort < b.data.sort
            -- end
            -- if a.type ~= b.type then
            --     return a.type < b.type
            -- end
            -- return a.index < b.index
            if a.type ~= b.type then
                return a.type > b.type
            else
                if a.type==EntranceType.Func then 
                    return a.data.sort < b.data.sort
                else
                    return a.pb.startTime < b.pb.startTime
                end
            end
        end)
    end
    return list
end

function ModelFunctionOpen:ParseActivityConfig(pb)
    local tab = string.split(pb.scrollConfig, ";")
    local data = {}
    for k, v in ipairs(tab) do
        local tab2 = string.split(v, "=")
        if tab2[1] == "1" then
            data.icon = tab2[2]
        elseif tab2[1] == "2" then
            data.iconTxt = tab2[2]
        elseif tab2[1] == "3" then
            data.cellBg = tab2[2]
        elseif tab2[1] == "4" then
            data.cellBgTxt = tab2[2]
        elseif tab2[1] == "5" then
            data.cellNameDec = tab2[2]
        end
    end
    data.sort = pb.sort
    return data
end

function ModelFunctionOpen:OpenForeshowPop()
    if not self._foreshowPopList then return end
    local aRef , bRef 
    table.sort(self._foreshowPopList,function(a,b)
        aRef = GameTable.ForeshowPopRef[a.refId]
        bRef = GameTable.ForeshowPopRef[b.refId]
        return aRef.sort<bRef.sort
    end)
    local info = table.remove(self._foreshowPopList,1)
    GF.OpenWnd("UIForeshowPop",{info = info})
end

