-- 功能开启的预告
function ModelFunctionOpen:GetFunctionOpenShowInfo()
    --插入
    local list = gModelInstance:GetInstanceFunctionRef()
    local showListData = {}
    for k, v in ipairs(list) do
        local isOpen = self:CheckIsOpened(v.functionId)
        if (not isOpen) and #showListData <= 2 then

            table.insert(showListData, v.functionId)
        end
    end

    --如果有信息就进行构建
    if #showListData > 0 then
        --functionId -> des
        showListData = self:CreateOpenShowInfo(showListData)
    end

    return showListData
end

function ModelFunctionOpen:CreateOpenShowInfo(showListData)
    --[17012]	[騎士大人，<color=#feeba7>#a1#</color>已開啟！]
    --[17013]	[冒險<color=#68e6ac> #a1#關 </color>後開啟新功能：<color=#fef01e>#a2#</color>]
    --[17016]	[再挑戰<color=#139057>#a1#關</color>，並且再通過<color=#139057>#a2#</color>天開啟<color=#139057>#a3#</color>！]
    --[17017]	[再挑戰<color=#139057>#a1#關</color>，或者再通過<color=#139057>#a2#</color>天開啟<color=#139057>#a3#</color>！]
    --[17018]	[騎士再提升<color=#68e6ac> #a1#級 </color>後開啟新功能：<color=#fef01e>#a2#</color>]
    --[17019]	[騎士再提升<color=#68e6ac> #a1#級 </color>，並且再通過<color=#139057>#a2#</color>天開啟<color=#139057>#a3#</color>！]

    --开服天数
    local serverDay = gLGameLogin:GetServerOpenDay()
    --当前通过
    local battleNode = gModelInstance:GetBattleNode()
    local curbattleNode = gModelInstance:GetLastBattleNode(1, battleNode)
    local iRef = gModelInstance:GetMissionCfg(curbattleNode)
    local num = iRef.num

    local playerlv = gModelPlayer:GetPlayerLv()

    local resultList = {}
    --就一个des
    for _, functionId in ipairs(showListData) do
        local showType = 1
        local battleNum = 0
        local openDay = 0
        local level = 0
        local foRef = self:GetFunctionOpenCfg(functionId)
        -- 并且部分的检查
        if not foRef then
            printInfoNR2("配置错误---","InstanceFunctionRef--配置的functionId"..functionId.."不存在FunctionOpenRef中")
        else
            if not string.isempty(foRef.open) then
                local open = string.split(foRef.open, ",")
                for j, condition in ipairs(open) do
                    local arr = string.split(condition, "=")
                    local type = tonumber(arr[1])

                    if type == 2 then
                        battleNum = tonumber(arr[2]) - num
                        showType = 2
                    elseif type == 11 then
                        openDay = tonumber(arr[2]) - serverDay

                    elseif type == 1 then

                        level = tonumber(arr[2]) - playerlv

                        showType = 5
                    end
                end

                if battleNum > 0 and openDay > 0 then
                    showType = 3
                end

                if level > 0 and openDay > 0 then
                    showType = 6
                end
                --
                if level < 0 and openDay > 0 then
                    level= 0
                    showType = 6
                end
            end
            -- 或的条件检查
            if not string.isempty(foRef.otherOpen) and (battleNum == 0 or openDay == 0) then
                local otherOpen = string.split(foRef.otherOpen, ",")
                for j, k in ipairs(otherOpen) do
                    local arr = string.split(k, "=")
                    local type = tonumber(arr[1])
                    if type == 2 then
                        battleNum = tonumber(arr[2]) - num
                        showType = 2
                    elseif type == 11 then
                        openDay = tonumber(arr[2]) - serverDay
                    end
                end
                showType = 4
            end


            --创建对应的des
            local name = ccLngText(foRef.name)
            local str
            if showType == 1 then
                str = string.replace(ccClientText(17012), name)
            elseif showType == 2 then
                str = string.replace(ccClientText(17013), battleNum, name)
            elseif showType == 3 then
                str = string.replace(ccClientText(17016), battleNum, openDay, name)
            elseif showType == 4 then
                str = string.replace(ccClientText(17017), battleNum, openDay, name)
            elseif showType == 5 then
                str = string.replace(ccClientText(17018), level, name)
            elseif showType == 6 then
                str = string.replace(ccClientText(17019), level, openDay, name)
            end

            table.insert(resultList, str)
        end


    end

    return resultList
end

