function ModelFunctionOpen:CheckIsOpenRes(refId)
    local cfg = GameTable.FeatureOpenRef[refId]
    if cfg then
        local resOpen = cfg.resOpen
        if not string.isempty(resOpen) then
            local isOpenRes = false
            local resType = LPlayerPrefs.GetLocalization()
            resOpen = string.split(resOpen,",")
            for i,v in ipairs(resOpen) do
                if resType == checknumber(v) then
                    isOpenRes = true
                    break
                end
            end
            return isOpenRes
        end
    end
    return true
end

